using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(entity =>
        {
            // Breaking change: discriminator property renamed from "Discriminator" to "$type".
            // Keep old name so existing documents are still queryable.
            entity.HasDiscriminator<string>("Discriminator");

            // Breaking change: id no longer includes discriminator (was "Blog|1", now "1").
            // Keep old composite format so existing documents are found.
            entity.HasDiscriminatorInJsonId();

            // Breaking change: key property now maps directly to JSON "id".
            // Keep the shadow __id property so the separate "Id" JSON field is preserved.
            entity.HasShadowId();

            // Breaking change: HasIndex now throws on Cosmos (was silently ignored).
            // Removed – Cosmos indexes all properties by default.
        });
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

